#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


    mat2 rot =  {  q5, q4,
                       -q4, q5 };

    vec3 txr = vec3(vUv,q2);

    float final_noise = 0;
    final_noise += (1.0/pow(2,0))*(texture3D(sampler_noisevol_hq, txr*pow(q3,0))*2-1);
    final_noise += (1.0/pow(2,1))*(texture3D(sampler_noisevol_hq, txr*pow(q3,1))*2-1);
    final_noise += (1.0/pow(2,2))*(texture3D(sampler_noisevol_hq, txr*pow(q3,2))*2-1);
    final_noise += (1.0/pow(2,3))*(texture3D(sampler_noisevol_hq, txr*pow(q3,3))*2-1);

    final_noise =  pow(final_noise,1);

    ret = texture(sampler_main, multiply(vUv-0.5,rot)*(1-vRadius*3.7*(1 - audioLowSmooth*0.3))*final_noise + 0.5).xyz;

    // darken (decay) over uTime
    ret = ret; //or try: ret -= 0.004;

  fragColor = ret;
}

